private static boolean ignoreQuote = false;
void read(Tokeniser t, CharacterReader r) throws IOException{
    while(!r.eof()){
        char ch = 0;
        if (!ignoreQuote) {
             ch = r.read();
             r.unread();
         }
        if(ch=='\''||ch=='"'){
           // System.out.println("Ch:"+ch+" "+r.getIndex());
            if (!ignoreQuote){
                ignoreQuote = true;
                 r.advance();
              continue;
          }else {
               ignoreQuote =false;
                r.advance();
             continue;
            }
        }
       if(!ignoreQuote) {
            if (r.matchesLetter()) {
                String name = r.consumeLetterSequence();
                t.tagPending.appendTagName(name.toLowerCase());
                t.dataBuffer.append(name);
                r.advance();
                continue;
            }
        }
      if (t.isAppropriateEndTagToken() && !r.isEmpty()) {
          char c = r.consume();
          switch (c) {
              case '\t':
              case '\n':
              case '\f':
              case ' ':
                  t.transition(BeforeAttributeName);
                  break;
              case '/':
                  t.transition(SelfClosingStartTag);
                  break;
              case '>':
                  t.emitTagPending();
                  t.transition(Data);
                  break;
              default:
                  t.dataBuffer.append(c);
                  anythingElse(t, r);
                  break;
          }
     } else {
        r.advance();
          continue;
      }
   }
}

